'use server'

import { cookies } from 'next/headers'
import { revalidatePath } from 'next/cache'

export async function toggleNotifications() {
  const cookieStore = await cookies()
  const current = cookieStore.get('notifications_enabled')?.value

  const newValue = current === 'true' ? 'false' : 'true'

  cookieStore.set('notifications_enabled', newValue, {
    maxAge: 60 * 60 * 24 * 365, // 1 year
    path: '/',
    sameSite: 'lax',
  })

  revalidatePath('/')
}

import { cookies } from 'next/headers'
import { ToggleForm } from './toggle-form'

export default async function Home() {
  const cookieStore = await cookies()
  const enabled = cookieStore.get('notifications_enabled')?.value === 'true'

  return (
    <main>
      <h1>Settings</h1>
      <p>Manage your notification preferences below.</p>

      <section>
        <h2>Notifications</h2>
        <p>
          Status:{' '}
          <strong>{enabled ? 'Enabled' : 'Disabled'}</strong>
        </p>
        <ToggleForm enabled={enabled} />
      </section>
    </main>
  )
}

'use client'

import { useFormStatus } from 'react-dom'
import { toggleNotifications } from './actions'

function SubmitButton({ enabled }: { enabled: boolean }) {
  const { pending } = useFormStatus()

  return (
    <button type="submit" disabled={pending} aria-pressed={enabled}>
      {pending ? 'Updating…' : enabled ? 'Disable Notifications' : 'Enable Notifications'}
    </button>
  )
}

export function ToggleForm({ enabled }: { enabled: boolean }) {
  return (
    <form action={toggleNotifications}>
      <SubmitButton enabled={enabled} />
    </form>
  )
}
